css:
* { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  width: 100%;
  height: 100%;
  background: transparent;
  font-family: -apple-system, "PingFang SC", "Helvetica Neue", sans-serif;
  overflow: hidden;
}

.wrap {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  align-items: center;
  padding: 4px;
}

/* ========== 頭像 + 耳機線 ========== */
.head {
  position: relative;
  width: 100%;
  height: 32%;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: flex-start;
  padding-top: 2px;
}

.avatars {
  display: flex;
  gap: 0;
  z-index: 2;
  position: relative;
}

.av {
  width: 60px;
  height: 60px;
  border-radius: 50%;
  object-fit: cover;
  border: 2.5px solid #fff;
  box-shadow: 0 2px 8px rgba(0,0,0,.18);
  background: #eee;
}

/* 兩個頭像互相疊壓 */
.av1 { margin-right: -10px; z-index: 2; }
.av2 { z-index: 1; }

.cords {
  position: absolute;
  top: 0;
  left: 50%;
  transform: translateX(-50%);
  width: 160px;
  height: 100%;
  pointer-events: none;
  z-index: 1;
}

.together-text {
  position: absolute;
  bottom: 0;
  left: 50%;
  transform: translateX(-50%);
  font-size: 11px;
  color: #888;
  white-space: nowrap;
  letter-spacing: .3px;
  z-index: 3;
  text-shadow: 0 1px 2px rgba(255,255,255,.7);
}
.together-text #together {
  color: #ff5a7a;
  font-weight: 700;
}

/* ========== iPod 本體（豎長方形） ========== */
.ipod {
  flex: 1;
  width: 68%;
  max-width: 200px;
  background: #fff;
  border-radius: 14px;
  padding: 10px 9px;
  display: flex;
  flex-direction: column;
  gap: 8px;
  box-shadow:
    inset 0 1px 0 rgba(255,255,255,1),
    inset 0 -2px 6px rgba(0,0,0,.04),
    0 6px 18px rgba(0,0,0,.18),
    0 1px 3px rgba(0,0,0,.08);
  border: 1px solid rgba(0,0,0,.06);
}

.screen {
  background: linear-gradient(180deg, #f4f6f8 0%, #e7ecef 100%);
  border-radius: 3px;
  padding: 4px 6px;
  flex: 0 0 42%;
  display: flex;
  flex-direction: column;
  gap: 3px;
  box-shadow:
    inset 0 1px 3px rgba(0,0,0,.18),
    inset 0 -1px 0 rgba(255,255,255,.6);
  color: #333;
  border: 1px solid #c8ccd0;
}

.screen-top {
  display: flex;
  justify-content: space-between;
  font-size: 8px;
  font-weight: 700;
  border-bottom: 1px solid rgba(0,0,0,.12);
  padding-bottom: 2px;
  color: #444;
}

.np {
  display: flex;
  gap: 6px;
  flex: 1;
  align-items: center;
  min-height: 0;
}

.cover {
  width: 40px;
  height: 40px;
  border-radius: 2px;
  object-fit: cover;
  box-shadow: 0 1px 3px rgba(0,0,0,.3);
  background: #888;
  flex-shrink: 0;
}

.info { flex: 1; min-width: 0; display: flex; flex-direction: column; gap: 1px; }
.song { font-size: 10px; font-weight: 700; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
.artist { font-size: 8px; color: #666; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }

.bottom-bar { display: flex; align-items: center; gap: 4px; font-size: 7px; color: #555; }
.bar { flex: 1; height: 3px; background: rgba(0,0,0,.1); border-radius: 2px; overflow: hidden; }
.bar-fill { height: 100%; width: 30%; background: linear-gradient(90deg, #4a9eff, #2b7de8); border-radius: 2px; transition: width .3s linear; }

.wheel {
  flex: 1;
  position: relative;
  aspect-ratio: 1;
  margin: 0 auto;
  max-height: 100%;
  background: radial-gradient(circle at 30% 25%, #ffffff 0%, #f0f0f2 50%, #d8d8dc 100%);
  border-radius: 50%;
  box-shadow:
    inset 0 2px 4px rgba(255,255,255,1),
    inset 0 -3px 6px rgba(0,0,0,.08),
    0 1px 3px rgba(0,0,0,.12);
  display: flex;
  align-items: center;
  justify-content: center;
}

.wheel-label.menu {
  position: absolute; top: 7%;
  font-size: 8px; font-weight: 700;
  color: #888; letter-spacing: 1px;
  user-select: none;
}

.wheel-btn {
  position: absolute;
  width: 18%; height: 18%;
  background-repeat: no-repeat;
  background-position: center;
  background-size: 75% 75%;
  cursor: pointer;
  opacity: .55;
  transition: opacity .15s, transform .1s;
}
.wheel-btn:active { transform: scale(.88); opacity: .9; }

.wheel-btn.prev {
  left: 8%;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'><path fill='%23555' d='M6 6h2v12H6zm3.5 6l8.5 6V6z'/></svg>");
}
.wheel-btn.next {
  right: 8%;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'><path fill='%23555' d='M16 6h2v12h-2zM6 18l8.5-6L6 6z'/></svg>");
}
.wheel-btn.play {
  bottom: 7%;
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'><path fill='%23555' d='M4 5h3v14H4zm6 0v14l11-7z'/></svg>");
}

.center {
  width: 38%; height: 38%;
  border-radius: 50%;
  background: radial-gradient(circle at 35% 30%, #ffffff 0%, #f5f5f7 60%, #e0e0e4 100%);
  box-shadow:
    inset 0 1px 2px rgba(255,255,255,1),
    inset 0 -1px 2px rgba(0,0,0,.08),
    0 1px 3px rgba(0,0,0,.18);
  cursor: pointer;
  transition: transform .1s;
}
.center:active { transform: scale(.94); }

* { box-sizing: border-box; margin: 0; padding: 0; }

html, body {
  width: 100%; height: 100%;
  background: transparent;
  font-family: -apple-system, "PingFang SC", sans-serif;
  overflow: hidden;
  display: flex;
  align-items: center;
  justify-content: center;
}

/* ===== 機身：豎版小巧 ===== */
.phone {
  width: 64%;
  max-width: 200px;
  height: 96%;
  background: linear-gradient(135deg, #e8e8ec 0%, #c8c8cc 50%, #dcdce0 100%);
  border-radius: 16px;
  padding: 4px 5px 5px;
  display: flex;
  flex-direction: column;
  gap: 3px;
  box-shadow:
    inset 0 1px 0 rgba(255,255,255,1),
    inset 0 -2px 4px rgba(0,0,0,.12),
    0 5px 14px rgba(0,0,0,.3);
  border: 1px solid rgba(0,0,0,.12);
}

/* 頂部 */
.top {
  position: relative;
  height: 14px;
  display: flex;
  align-items: center;
  justify-content: center;
  flex-shrink: 0;
}
.speaker {
  position: absolute; top: 1px; left: 50%;
  transform: translateX(-50%);
  width: 24%; height: 2.5px;
  background: #5a5a60;
  border-radius: 2px;
  box-shadow: inset 0 1px 1px rgba(0,0,0,.5);
}
.logo {
  font-size: 6.5px;
  font-weight: 800;
  color: #4a4a52;
  letter-spacing: 1px;
  margin-top: 4px;
}
.smiley {
  position: absolute; right: 0; top: 1px;
  width: 11px; height: 11px;
  background: #ffd84a;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 7px; color: #333;
  box-shadow: 0 1px 2px rgba(0,0,0,.2);
}

/* ===== LCD 螢幕 ===== */
.lcd {
  flex: 0 0 36%;
  background: repeating-linear-gradient(0deg, #a8d860 0, #a8d860 1.5px, #9fce58 1.5px, #9fce58 2px);
  border-radius: 4px;
  padding: 3px 5px;
  display: flex;
  flex-direction: column;
  gap: 1px;
  box-shadow: inset 0 2px 4px rgba(0,0,0,.35), inset 0 0 8px rgba(80,120,40,.4);
  border: 1.5px solid #5a5a60;
  font-family: "VT323", "Press Start 2P", "Courier New", monospace;
  color: #1a2a10;
  overflow: hidden;
}
.lcd-top {
  display: flex; justify-content: space-between; align-items: center;
  font-size: 7.5px; font-weight: 700;
  border-bottom: 1px solid rgba(0,0,0,.18);
  padding-bottom: 1px;
}
.lcd-top .batt { letter-spacing: -2px; }
.lcd-body {
  flex: 1;
  display: flex;
  align-items: center;
  justify-content: center;
  text-align: center;
  font-size: 15px;
  line-height: 1.4;
  font-weight: 700;
  overflow: hidden;
  padding: 2px 0;
  letter-spacing: .3px;
  min-height: 0;
}
.msg-text { width: 100%; word-break: break-word; text-align: center; }
.msg-text.hint { font-size: 12px; opacity: .7; }
.msg-text.big { font-size: 18px; font-weight: 800; letter-spacing: 1px; }
.hint-sm { font-size: 8px; opacity: .65; margin-top: 2px; }
.lcd-bottom {
  font-size: 6.5px; font-weight: 700;
  border-top: 1px solid rgba(0,0,0,.18);
  padding-top: 1px;
}
.bill-list { font-size: 7px; line-height: 1.4; }
.bill-item { display: flex; justify-content: space-between; align-items: center; border-bottom: 1px dashed rgba(0,0,0,.2); }
.bill-item .del { color: #c83030; cursor: pointer; font-weight: 800; padding: 0 2px; }

/* ===== 軟鍵區 ===== */
.soft-row {
  flex: 0 0 13%;
  min-height: 20px;
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 2px;
}
.soft {
  width: 28%; height: 100%;
  background: linear-gradient(180deg, #2a2a30 0%, #1a1a20 100%);
  border-radius: 9px 9px 5px 5px;
  display: flex; align-items: center; justify-content: center;
  cursor: pointer;
  box-shadow: inset 0 1px 0 rgba(255,255,255,.15), 0 1px 2px rgba(0,0,0,.3);
}
.soft:active { transform: translateY(1px); }
.ic { width: 14px; height: 14px; background-repeat: no-repeat; background-position: center; background-size: contain; }
.ic-call {
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'><path fill='%234ade80' d='M6.6 10.8a15 15 0 006.6 6.6l2.2-2.2c.3-.3.7-.4 1-.2a11 11 0 003.5.6c.6 0 1 .4 1 1V20c0 .6-.4 1-1 1A17 17 0 013 4c0-.6.4-1 1-1h3.5c.6 0 1 .4 1 1 0 1.2.2 2.4.6 3.5.1.3 0 .7-.2 1z'/></svg>");
}
.ic-end {
  background-image: url("data:image/svg+xml;utf8,<svg xmlns='http://www.w3.org/2000/svg' viewBox='0 0 24 24'><path fill='%23ff5050' d='M6.6 10.8a15 15 0 006.6 6.6l2.2-2.2c.3-.3.7-.4 1-.2a11 11 0 003.5.6c.6 0 1 .4 1 1V20c0 .6-.4 1-1 1A17 17 0 013 4c0-.6.4-1 1-1h3.5c.6 0 1 .4 1 1 0 1.2.2 2.4.6 3.5.1.3 0 .7-.2 1z' transform='rotate(135 12 12)'/></svg>");
}

/* 中央方向鍵 */
.dpad {
  width: 38%; height: 100%;
  background: radial-gradient(ellipse at 50% 30%, #f4f4f8 0%, #c4c4cc 70%, #a4a4ac 100%);
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  box-shadow:
    inset 0 1px 1px rgba(255,255,255,.95),
    inset 0 -1px 2px rgba(0,0,0,.2),
    0 1px 2px rgba(0,0,0,.3);
}
.dpad-c {
  width: 50%; height: 55%;
  background: linear-gradient(180deg, #2a2a30, #15151a);
  border-radius: 4px;
  box-shadow: inset 0 1px 1px rgba(255,255,255,.1), inset 0 -1px 2px rgba(0,0,0,.5);
}

/* ===== 鍵盤（白鍵） ===== */
.keypad {
  flex: 1;
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  grid-template-rows: repeat(4, 1fr);
  gap: 2px;
  background: #2a2a30;
  padding: 2px;
  border-radius: 5px;
  box-shadow: inset 0 1px 3px rgba(0,0,0,.5);
  min-height: 0;
}
.key {
  background: linear-gradient(180deg, #ffffff 0%, #e0e0e4 100%);
  border-radius: 3px;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 3px;
  cursor: pointer;
  user-select: none;
  color: #1a1a20;
  box-shadow:
    inset 0 1px 0 rgba(255,255,255,1),
    inset 0 -1px 1px rgba(0,0,0,.15),
    0 1px 1px rgba(0,0,0,.15);
  transition: transform .08s, box-shadow .08s;
  padding: 1px 2px;
  min-width: 0;
  overflow: hidden;
  border: 1px solid rgba(0,0,0,.08);
}
.key.pressed,
.key:active {
  transform: translateY(1px);
  box-shadow: inset 0 1px 3px rgba(0,0,0,.2);
  background: linear-gradient(180deg, #e8e8ec 0%, #d0d0d4 100%);
}
.key b {
  font-size: 11px;
  font-weight: 800;
  font-family: "Arial Black", sans-serif;
  line-height: 1;
  color: #1a1a20;
}
.key i {
  font-size: 7px;
  font-style: normal;
  line-height: 1;
}

.my-custom-box {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  height: 100%;
  background: #fff;
  border-radius: 20px;
}
.my-custom-box img {
  width: 50px;
  height: 50px;
  border-radius: 50%;
}
